128→    override fun getAccountFlow(accountUuid: String): Flow<Account> {
129→        return callbackFlow {
130→            val initialAccount = getAccount(accountUuid)
131→            if (initialAccount == null) {
132→                close()
133→                return@callbackFlow
134→            }
135→
136→            send(initialAccount)
137→
138→            val listener = AccountsChangeListener {
139→                val account = getAccount(accountUuid)
140→                if (account != null) {
141→                    trySendBlocking(account)
142→                } else {
143→                    close()
144→                }
145→            }
146→            addOnAccountsChangeListener(listener)
147→
148→            awaitClose {
149→                removeOnAccountsChangeListener(listener)
150→            }
151→        }.buffer(capacity = Channel.CONFLATED)
152→            .flowOn(backgroundDispatcher)
153→    }
154→
155→    @OptIn(ExperimentalCoroutinesApi::class)
156→    override fun getAccountsFlow(): Flow<List<Account>> {
157→        return callbackFlow {
158→            send(completeAccounts)
159→
160→            val listener = AccountsChangeListener {
161→                trySendBlocking(completeAccounts)
162→            }
163→            addOnAccountsChangeListener(listener)
164→
165→            awaitClose {
166→                removeOnAccountsChangeListener(listener)
167→            }
168→        }.buffer(capacity = Channel.CONFLATED)
169→            .flowOn(backgroundDispatcher)
170→    }
